struct FocusStateDemo: View {
    enum Field: Hashable { case username, password }
    @State private var username = ""
    @State private var password = ""
    @FocusState private var focusedField: {valueShape == "Bool" ? "Bool" : "Field?"}

    var body: some View {
        Form {
            TextField("Username", text: $username)
                .{boundModifier == "focused(_:)" ? "focused($focusedField)" : "focused($focusedField, equals: .username)"}
            SecureField("Password", text: $password)
                .focused($focusedField, equals: .password)
            Button("Next") { focusedField = {programmaticFocus} }
        }
    }
}

